from flask import Flask, session, request, jsonify
from functools import wraps
import redis
import hashlib
import json
import pickle
import os
from datetime import timedelta

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', 'your-secret-key-here-change-in-production')
app.config['SESSION_TYPE'] = 'redis'
app.config['PERMANENT_SESSION_LIFETIME'] = timedelta(hours=24)

redis_client = redis.Redis(
    host='localhost',
    port=6379,
    db=0,
    decode_responses=False
)

redis_session_client = redis.Redis(
    host='localhost',
    port=6379,
    db=1,
    decode_responses=True
)


class RedisSessionInterface:
    def __init__(self, redis_client, prefix='session:'):
        self.redis = redis_client
        self.prefix = prefix

    def generate_sid(self):
        return os.urandom(24).hex()

    def get_session_id(self):
        return request.cookies.get('session_id')

    def open_session(self, app, request):
        sid = request.cookies.get('session_id')
        if sid:
            session_data = self.redis.get(f'{self.prefix}{sid}')
            if session_data:
                return json.loads(session_data)
        return {}

    def save_session(self, app, session_data, response):
        sid = request.cookies.get('session_id')
        if not sid:
            sid = self.generate_sid()
            response.set_cookie('session_id', sid, httponly=True, max_age=86400)
        
        self.redis.setex(
            f'{self.prefix}{sid}',
            86400,
            json.dumps(session_data)
        )

    def delete_session(self, sid):
        self.redis.delete(f'{self.prefix}{sid}')


session_interface = RedisSessionInterface(redis_session_client)


@app.before_request
def load_session():
    session.update(session_interface.open_session(app, request))


@app.after_request
def save_session_data(response):
    session_interface.save_session(app, dict(session), response)
    return response


def cache_result(expiration=300, key_prefix='cache'):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            cache_key_data = f"{key_prefix}:{func.__name__}:{str(args)}:{str(kwargs)}"
            cache_key = hashlib.md5(cache_key_data.encode()).hexdigest()
            
            cached_value = redis_client.get(cache_key)
            if cached_value is not None:
                return pickle.loads(cached_value)
            
            result = func(*args, **kwargs)
            
            redis_client.setex(
                cache_key,
                expiration,
                pickle.dumps(result)
            )
            
            return result
        return wrapper
    return decorator


def invalidate_cache(key_prefix='cache', pattern=None):
    if pattern:
        keys = redis_client.keys(f"{key_prefix}:{pattern}*")
        if keys:
            redis_client.delete(*keys)
    else:
        keys = redis_client.keys(f"{key_prefix}:*")
        if keys:
            redis_client.delete(*keys)


@cache_result(expiration=600, key_prefix='user_data')
def get_user_from_database(user_id):
    import time
    time.sleep(2)
    return {
        'id': user_id,
        'name': f'User {user_id}',
        'email': f'user{user_id}@example.com',
        'role': 'user'
    }


@cache_result(expiration=300, key_prefix='products')
def get_products_from_database(category=None, limit=10):
    import time
    time.sleep(1.5)
    products = []
    for i in range(limit):
        products.append({
            'id': i,
            'name': f'Product {i}',
            'category': category or 'general',
            'price': 10.99 * (i + 1)
        })
    return products


@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    if username and password:
        session['username'] = username
        session['user_id'] = hashlib.md5(username.encode()).hexdigest()[:8]
        session['logged_in'] = True
        
        return jsonify({
            'message': 'Login successful',
            'username': username,
            'session_id': request.cookies.get('session_id')
        }), 200
    
    return jsonify({'error': 'Invalid credentials'}), 401


@app.route('/logout', methods=['POST'])
def logout():
    sid = request.cookies.get('session_id')
    if sid:
        session_interface.delete_session(sid)
    
    session.clear()
    
    response = jsonify({'message': 'Logout successful'})
    response.set_cookie('session_id', '', expires=0)
    return response


@app.route('/session', methods=['GET'])
def get_session():
    return jsonify({
        'session_data': dict(session),
        'session_id': request.cookies.get('session_id')
    })


@app.route('/user/<user_id>', methods=['GET'])
def get_user(user_id):
    if not session.get('logged_in'):
        return jsonify({'error': 'Not authenticated'}), 401
    
    user_data = get_user_from_database(user_id)
    return jsonify(user_data)


@app.route('/products', methods=['GET'])
def get_products():
    category = request.args.get('category')
    limit = int(request.args.get('limit', 10))
    
    products = get_products_from_database(category=category, limit=limit)
    return jsonify({'products': products})


@app.route('/cache/invalidate', methods=['POST'])
def invalidate_cache_endpoint():
    if not session.get('logged_in'):
        return jsonify({'error': 'Not authenticated'}), 401
    
    data = request.get_json() or {}
    key_prefix = data.get('key_prefix', 'cache')
    pattern = data.get('pattern')
    
    invalidate_cache(key_prefix=key_prefix, pattern=pattern)
    
    return jsonify({'message': 'Cache invalidated successfully'})


@app.route('/cache/stats', methods=['GET'])
def cache_stats():
    info = redis_client.info('stats')
    keyspace = redis_client.info('keyspace')
    
    return jsonify({
        'stats': {
            'total_connections_received': info.get('total_connections_received'),
            'total_commands_processed': info.get('total_commands_processed'),
            'keyspace_hits': info.get('keyspace_hits'),
            'keyspace_misses': info.get('keyspace_misses'),
        },
        'keyspace': keyspace
    })


@app.route('/set_cache', methods=['POST'])
def set_cache():
    data = request.get_json()
    key = data.get('key')
    value = data.get('value')
    expiration = data.get('expiration', 300)
    
    if not key or value is None:
        return jsonify({'error': 'Key and value are required'}), 400
    
    redis_client.setex(
        f'custom:{key}',
        expiration,
        pickle.dumps(value)
    )
    
    return jsonify({'message': 'Cache set successfully', 'key': key})


@app.route('/get_cache/<key>', methods=['GET'])
def get_cache(key):
    cached_value = redis_client.get(f'custom:{key}')
    
    if cached_value is None:
        return jsonify({'error': 'Key not found'}), 404
    
    return jsonify({
        'key': key,
        'value': pickle.loads(cached_value)
    })


@app.route('/health', methods=['GET'])
def health_check():
    try:
        redis_client.ping()
        redis_session_client.ping()
        return jsonify({
            'status': 'healthy',
            'redis': 'connected'
        })
    except Exception as e:
        return jsonify({
            'status': 'unhealthy',
            'redis': 'disconnected',
            'error': str(e)
        }), 503


